class Solution {
public:
    int findMinimumOperations(string s1, string s2, string s3) {
        int n = s1.size();
        int m = s2.size();
        int p = s3.size();

        int dp[n + 1][m + 1][p + 1];

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                for (int k = 0; k <= p; k++) {
                    if (i == 0 || j == 0 || k == 0) {
                        dp[i][j][k] = 0;
                    } else if (s1[i - 1] == s2[j - 1] && s2[j - 1] == s3[k - 1]) {
                        dp[i][j][k] = 1 + min(min(dp[i - 1][j - 1][k - 1], dp[i - 1][j][k - 1]), min(dp[i - 1][j - 1][k], dp[i][j - 1][k - 1]));
                    } else {
                        dp[i][j][k] = 1 + min(min(dp[i - 1][j - 1][k - 1], dp[i - 1][j][k - 1]), min(dp[i - 1][j - 1][k], dp[i][j - 1][k - 1]));
                    }
                }
            }
        }

        return dp[n][m][p] == 0 ? 0 : n + m + p - dp[n][m][p];
    }
};
